export async function analyticsCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const dir = resolve(args[1] && !args[1].startsWith("--") ? args[1] : ".");
  const days = parseInt(getFlag("--days") || "30", 10);
  const db = new RagDB(dir);
  const analytics = db.getAnalytics(days);

  const zeroCount = analytics.zeroResultQueries.reduce((s, q) => s + q.count, 0);
  const zeroRate = analytics.totalQueries > 0
    ? ((zeroCount / analytics.totalQueries) * 100).toFixed(0)
    : "0";

  cli.log(`Search analytics (last ${days} days):`);
  cli.log(`  Total queries:    ${analytics.totalQueries}`);
  cli.log(`  Avg results:      ${analytics.avgResultCount.toFixed(1)}`);
  cli.log(`  Avg top score:    ${analytics.avgTopScore?.toFixed(2) ?? "n/a"}`);
  cli.log(`  Zero-result rate: ${zeroRate}% (${zeroCount} queries)`);

  if (analytics.topSearchedTerms.length > 0) {
    cli.log("\nTop searches:");
    for (const t of analytics.topSearchedTerms) {
      cli.log(`  ${t.count}× "${t.query}"`);
    }
  }

  if (analytics.zeroResultQueries.length > 0) {
    cli.log("\nZero-result queries (consider indexing these topics):");
    for (const q of analytics.zeroResultQueries) {
      cli.log(`  ${q.count}× "${q.query}"`);
    }
  }

  if (analytics.lowScoreQueries.length > 0) {
    cli.log("\nLow-relevance queries (top score < 0.3):");
    for (const q of analytics.lowScoreQueries) {
      cli.log(`  "${q.query}" (score: ${q.topScore.toFixed(2)})`);
    }
  }

  // Trend comparison vs prior period
  const trend = db.getAnalyticsTrend(days);
  if (trend.previous.totalQueries > 0 || trend.current.totalQueries > 0) {
    const arrow = (delta: number) => delta > 0 ? `+${delta}` : `${delta}`;
    const pctArrow = (delta: number) =>
      delta > 0 ? `+${(delta * 100).toFixed(1)}%` : `${(delta * 100).toFixed(1)}%`;

    cli.log(`\nTrend (current ${days}d vs prior ${days}d):`);
    cli.log(`  Queries:          ${trend.current.totalQueries} (${arrow(trend.delta.queries)})`);
    if (trend.delta.avgTopScore !== null) {
      cli.log(`  Avg top score:    ${trend.current.avgTopScore?.toFixed(2)} (${trend.delta.avgTopScore >= 0 ? "+" : ""}${trend.delta.avgTopScore.toFixed(2)})`);
    }
    cli.log(`  Zero-result rate: ${(trend.current.zeroResultRate * 100).toFixed(0)}% (${pctArrow(trend.delta.zeroResultRate)})`);
  }

  db.close();
}

export async function annotationsCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const dir = resolve(args[1] && !args[1].startsWith("--") ? args[1] : getFlag("--dir") || ".");
  const filterPath = getFlag("--path");
  const db = new RagDB(dir);
  const annotations = db.getAnnotations(filterPath);

  if (annotations.length === 0) {
    cli.log(filterPath ? `No annotations for ${filterPath}.` : "No annotations found.");
    db.close();
    return;
  }

  for (const a of annotations) {
    const target = a.symbolName ? `${a.path}  •  ${a.symbolName}` : a.path;
    const authorStr = a.author ? ` [${a.author}]` : "";
    cli.log(`#${a.id}  ${target}${authorStr}`);
    cli.log(`  ${a.note}`);
    cli.log(`  (${a.updatedAt})`);
    cli.log();
  }

  db.close();
}

export function appendIncrementalLog(
  wikiDir: string,
  sinceRef: string,
  newRef: string,
  changedFileCount: number,
  report: StalenessReport,
): void {
  const { stale, added, removed } = report;
  const byOrder = (a: { order: number }, b: { order: number }) =>
    a.order - b.order;

  let entry =
    `## ${isoStamp()} — Incremental update (\`${sinceRef}\` → \`${newRef}\`)\n\n` +
    `${changedFileCount} file${plural(changedFileCount)} changed. ` +
    `${stale.length} regenerated, ${added.length} added, ${removed.length} removed.\n`;

  if (stale.length === 0 && added.length === 0 && removed.length === 0) {
    entry += `\nNo wiki pages invalidated by the changed files.\n`;
    append(wikiDir, entry);
    return;
  }

  if (stale.length > 0) {
    entry += `\n### Regenerated\n\n`;
    for (const d of [...stale].sort(byOrder)) {
      const kind = d.page.focus ?? d.page.kind;
      entry += `- \`${d.wikiPath}\` — ${d.page.title} (${kind}, ${d.page.depth})\n`;
      entry += `  - trigger: ${d.triggers.map((t) => `\`${t}\``).join(", ")}\n`;
    }
  }

  if (added.length > 0) {
    entry += `\n### Added\n\n`;
    for (const d of [...added].sort(byOrder)) {
      const kind = d.page.focus ?? d.page.kind;
      entry += `- \`${d.wikiPath}\` — ${d.page.title} (${kind}, ${d.page.depth})\n`;
    }
  }

  if (removed.length > 0) {
    entry += `\n### Removed\n\n`;
    for (const r of removed) {
      entry += `- \`${r.wikiPath}\` — ${r.page.title}\n`;
    }
  }

  append(wikiDir, entry);
}

export function appendInitLog(
  wikiDir: string,
  gitRef: string,
  manifest: PageManifest,
): void {
  const counts: Record<string, number> = {};
  for (const p of Object.values(manifest.pages)) {
    counts[p.tier] = (counts[p.tier] ?? 0) + 1;
  }
  const breakdown = Object.entries(counts)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([tier, count]) => `${count} ${tier}`)
    .join(", ");

  const entry =
    `## ${isoStamp()} — Full initialization (\`${gitRef}\`)\n\n` +
    `${manifest.pageCount} pages generated` +
    (breakdown ? ` (${breakdown}).\n` : `.\n`);

  append(wikiDir, entry);
}

export async function benchmarkCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const file = args[1];
  if (!file) {
    cli.error("Usage: mimirs benchmark <file> [--dir D] [--top N]");
    process.exit(1);
  }

  const dir = resolve(getFlag("--dir") || ".");
  const db = new RagDB(dir);
  const config = await loadConfig(dir);
  const top = parseInt(getFlag("--top") || String(config.benchmarkTopK), 10);

  const queries = await loadBenchmarkQueries(resolve(file));
  cli.log(`Running ${queries.length} benchmark queries against ${dir}...\n`);

  const summary = await runBenchmark(queries, db, dir, top);
  cli.log(formatBenchmarkReport(summary, top));

  db.close();

  // Exit with non-zero if below thresholds
  if (summary.recallAtK < config.benchmarkMinRecall || summary.mrr < config.benchmarkMinMrr) {
    process.exit(1);
  }
}

export function buildIdToPathMap(pathToId: Map<string, number>): Map<number, string> {
  const map = new Map<number, string>();
  for (const [path, id] of pathToId) {
    map.set(id, path);
  }
  return map;
}

export async function cleanupCommand(args: string[]) {
  const dir = resolve(args[1] && !args[1].startsWith("--") ? args[1] : ".");
  const autoYes = args.includes("--yes") || args.includes("-y");

  // Collect what we'd remove
  const pending: (() => Promise<string | null>)[] = [];

  // .mimirs/ directory
  const ragDir = join(dir, ".mimirs");
  if (existsSync(ragDir)) {
    pending.push(async () => {
      await rm(ragDir, { recursive: true, force: true });
      return "Deleted .mimirs/ directory";
    });
  }

  // MCP configs
  pending.push(() => removeMcpEntry(join(dir, ".mcp.json")));
  pending.push(() => removeMcpEntry(join(dir, ".cursor", "mcp.json")));
  pending.push(() => removeMcpEntry(join(homedir(), ".codeium", "windsurf", "mcp_config.json")));
  pending.push(() => removeMcpEntry(join(homedir(), ".codeium", "mcp_config.json")));

  // Agent instruction files
  pending.push(() => removeInstructionsBlock(join(dir, "CLAUDE.md")));
  pending.push(() => removeOwnedFile(join(dir, ".cursor", "rules", "mimirs.mdc")));
  pending.push(() => removeOwnedFile(join(dir, ".windsurf", "rules", "mimirs.md")));
  pending.push(() => removeInstructionsBlock(join(dir, ".github", "copilot-instructions.md")));

  // .gitignore
  pending.push(() => removeGitignoreEntry(dir));

  if (!autoYes) {
    cli.log("This will remove all mimirs files from this project:\n");
    cli.log("  - .mimirs/ directory (index database & config)");
    cli.log("  - mimirs entries from MCP configs (.mcp.json, .cursor/mcp.json, windsurf)");
    cli.log("  - Agent instructions (CLAUDE.md block, .cursor/rules/mimirs.mdc, etc.)");
    cli.log("  - .mimirs/ entry from .gitignore");
    cli.log();
    const ok = await confirm("Proceed? [y/N] ");
    if (!ok) {
      cli.log("Aborted.");
      return;
    }
  }

  const actions: string[] = [];
  for (const fn of pending) {
    const result = await fn();
    if (result) actions.push(result);
  }

  if (actions.length === 0) {
    cli.log("Nothing to clean up — no mimirs files found.");
  } else {
    for (const action of actions) cli.log(`  ${action}`);
    cli.log(`\nCleaned up ${actions.length} item(s).`);
  }
}

