export function cliProgress(msg: string, opts?: { transient?: boolean }): void {
  // file:start / file:done are bookkeeping for quiet mode; verbose already
  // shows per-file Indexing/Skipped/Indexed messages.
  if (msg.startsWith("file:")) return;

  if (opts?.transient) {
    writeTransient(msg);
  } else {
    clearTransient();
    cli.log(msg);
  }
}

export function confirm(question: string): Promise<boolean> {
  const rl = createInterface({ input: process.stdin, output: process.stdout });
  return new Promise((res) => {
    rl.question(question, (answer) => {
      rl.close();
      res(answer.trim().toLowerCase() !== "n");
    });
  });
}

export function createCheckpoint(
  db: Database,
  sessionId: string,
  turnIndex: number,
  timestamp: string,
  type: string,
  title: string,
  summary: string,
  filesInvolved: string[],
  tags: string[],
  embedding: Float32Array
): number {
  let checkpointId = 0;

  const tx = db.transaction(() => {
    db.run(
      `INSERT INTO conversation_checkpoints
       (session_id, turn_index, timestamp, type, title, summary, files_involved, tags, embedding)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      [
        sessionId,
        turnIndex,
        timestamp,
        type,
        title,
        summary,
        JSON.stringify(filesInvolved),
        JSON.stringify(tags),
        null,
      ]
    );

    checkpointId = Number(
      db.query<{ id: number }, []>("SELECT last_insert_rowid() as id").get()!.id
    );

    db.run(
      "INSERT INTO vec_checkpoints (checkpoint_id, embedding) VALUES (?, ?)",
      [checkpointId, new Uint8Array(embedding.buffer)]
    );
  });

  tx();
  return checkpointId;
}

