export async function indexCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const dir = resolve(args[1] && !args[1].startsWith("--") ? args[1] : ".");
  const verbose = args.includes("--verbose") || args.includes("-v");
  const db = new RagDB(dir);
  const config = await loadConfig(dir);
  applyEmbeddingConfig(config);

  const patternsStr = getFlag("--patterns");
  if (patternsStr) {
    config.include = patternsStr.split(",").map((p) => p.trim());
  }

  cli.log(`Indexing ${dir}...`);
  const startTime = Date.now();

  let quietProgress: ReturnType<typeof createQuietProgress> | null = null;

  const progress = verbose ? cliProgress : (msg: string, opts?: { transient?: boolean }) => {
    const foundMatch = msg.match(/^Found (\d+) files to index$/);
    if (foundMatch) {
      quietProgress = createQuietProgress(parseInt(foundMatch[1], 10));
    }

    if (quietProgress) {
      quietProgress(msg, opts);
    } else {
      cliProgress(msg, opts);
    }
  };

  const result = await indexDirectory(dir, db, config, progress);

  const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
  cli.log(
    `\nDone: ${result.indexed} indexed, ${result.skipped} skipped, ${result.pruned} pruned (${elapsed}s)`
  );
  if (result.errors.length > 0) {
    cli.error(`Errors: ${result.errors.join("\n  ")}`);
  }
  db.close();
}

export function insertChunkBatch(
  db: Database,
  fileId: number,
  chunks: EmbeddedChunk[],
  startIndex: number
) {
  const tx = db.transaction(() => {
    for (let i = 0; i < chunks.length; i++) {
      const { snippet, embedding, entityName, chunkType, startLine, endLine, contentHash, parentId } = chunks[i];
      db.run(
        "INSERT INTO chunks (file_id, chunk_index, snippet, entity_name, chunk_type, start_line, end_line, content_hash, parent_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
        [fileId, startIndex + i, snippet, entityName ?? null, chunkType ?? null, startLine ?? null, endLine ?? null, contentHash ?? null, parentId ?? null]
      );
      const chunkId = Number(
        db.query<{ id: number }, []>("SELECT last_insert_rowid() as id").get()!.id
      );
      db.run(
        "INSERT INTO vec_chunks (chunk_id, embedding) VALUES (?, ?)",
        [chunkId, new Uint8Array(embedding.buffer)]
      );
    }
  });
  tx();
}

export function insertCommitBatch(db: Database, commits: GitCommitInsert[]) {
  const tx = db.transaction(() => {
    for (const c of commits) {
      db.run(
        `INSERT OR IGNORE INTO git_commits
         (hash, short_hash, message, author_name, author_email, date,
          files_changed, insertions, deletions, is_merge, refs, diff_summary, indexed_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        [
          c.hash,
          c.shortHash,
          c.message,
          c.authorName,
          c.authorEmail,
          c.date,
          JSON.stringify(c.filesChanged.map((f) => f.path)),
          c.insertions,
          c.deletions,
          c.isMerge ? 1 : 0,
          JSON.stringify(c.refs),
          c.diffSummary,
          new Date().toISOString(),
        ]
      );

      const inserted = db.query<{ c: number }, []>("SELECT changes() as c").get()!.c;
      if (inserted === 0) continue;

      const commitId = Number(
        db.query<{ id: number }, []>("SELECT last_insert_rowid() as id").get()!.id
      );

      // Insert vector embedding
      db.run(
        "INSERT INTO vec_git_commits (commit_id, embedding) VALUES (?, ?)",
        [commitId, new Uint8Array(c.embedding.buffer)]
      );

      // Insert per-file stats
      for (const f of c.filesChanged) {
        db.run(
          "INSERT OR IGNORE INTO git_commit_files (commit_id, file_path, insertions, deletions) VALUES (?, ?, ?, ?)",
          [commitId, f.path, f.insertions, f.deletions]
        );
      }
    }
  });
  tx();
}

export function insertTurn(
  db: Database,
  sessionId: string,
  turnIndex: number,
  timestamp: string,
  userText: string,
  assistantText: string,
  toolsUsed: string[],
  filesReferenced: string[],
  tokenCost: number,
  summary: string,
  chunks: { snippet: string; embedding: Float32Array }[]
): number {
  let turnId = 0;

  const tx = db.transaction(() => {
    db.run(
      `INSERT OR IGNORE INTO conversation_turns
       (session_id, turn_index, timestamp, user_text, assistant_text, tools_used, files_referenced, token_cost, summary)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      [
        sessionId,
        turnIndex,
        timestamp,
        userText,
        assistantText,
        JSON.stringify(toolsUsed),
        JSON.stringify(filesReferenced),
        tokenCost,
        summary,
      ]
    );

    // If the INSERT was ignored (duplicate), changes() returns 0
    const inserted = db.query<{ c: number }, []>("SELECT changes() as c").get()!.c;
    if (inserted === 0) return;

    turnId = Number(
      db.query<{ id: number }, []>("SELECT last_insert_rowid() as id").get()!.id
    );

    for (let i = 0; i < chunks.length; i++) {
      const { snippet, embedding } = chunks[i];
      db.run(
        "INSERT INTO conversation_chunks (turn_id, chunk_index, snippet) VALUES (?, ?, ?)",
        [turnId, i, snippet]
      );
      const chunkId = Number(
        db.query<{ id: number }, []>("SELECT last_insert_rowid() as id").get()!.id
      );
      db.run(
        "INSERT INTO vec_conversation (chunk_id, embedding) VALUES (?, ?)",
        [chunkId, new Uint8Array(embedding.buffer)]
      );
    }
  });

  tx();
  return turnId;
}

export function listCheckpoints(
  db: Database,
  sessionId?: string,
  type?: string,
  limit: number = 20
): CheckpointRow[] {
  let sql = "SELECT * FROM conversation_checkpoints WHERE 1=1";
  const params: (string | number)[] = [];

  if (sessionId) {
    sql += " AND session_id = ?";
    params.push(sessionId);
  }
  if (type) {
    sql += " AND type = ?";
    params.push(type);
  }

  sql += " ORDER BY timestamp DESC LIMIT ?";
  params.push(limit);

  return db
    .query<
      { id: number; session_id: string; turn_index: number; timestamp: string; type: string; title: string; summary: string; files_involved: string; tags: string },
      (string | number)[]
    >(sql)
    .all(...params)
    .map((r) => ({
      id: r.id,
      sessionId: r.session_id,
      turnIndex: r.turn_index,
      timestamp: r.timestamp,
      type: r.type,
      title: r.title,
      summary: r.summary,
      filesInvolved: JSON.parse(r.files_involved || "[]"),
      tags: JSON.parse(r.tags || "[]"),
    }));
}

export async function loadBenchmarkQueries(path: string): Promise<BenchmarkQuery[]> {
  const raw = await readFile(path, "utf-8");
  const parsed = JSON.parse(raw);

  if (!Array.isArray(parsed)) {
    throw new Error("Benchmark file must be a JSON array of { query, expected } objects");
  }

  for (const entry of parsed) {
    if (!entry.query || !Array.isArray(entry.expected) || entry.expected.length === 0) {
      throw new Error(`Invalid benchmark entry: ${JSON.stringify(entry)}. Each entry needs "query" (string) and "expected" (string[])`);
    }
  }

  return parsed;
}

export async function loadEvalTasks(path: string): Promise<EvalTask[]> {
  const raw = await readFile(path, "utf-8");
  const parsed = JSON.parse(raw);

  if (!Array.isArray(parsed)) {
    throw new Error("Eval file must be a JSON array of { task, grading } objects");
  }

  for (const entry of parsed) {
    if (!entry.task || !entry.grading) {
      throw new Error(`Invalid eval entry: ${JSON.stringify(entry)}. Each entry needs "task" (string) and "grading" (string)`);
    }
  }

  return parsed;
}

