export function mergeEmbeddings(embeddings: Float32Array[]): Float32Array {
  const dim = embeddings[0].length;
  const avg = new Float32Array(dim);
  for (const emb of embeddings) {
    for (let i = 0; i < dim; i++) avg[i] += emb[i];
  }
  for (let i = 0; i < dim; i++) avg[i] /= embeddings.length;
  let norm = 0;
  for (let i = 0; i < dim; i++) norm += avg[i] * avg[i];
  norm = Math.sqrt(norm);
  if (norm > 0) for (let i = 0; i < dim; i++) avg[i] /= norm;
  return avg;
}

export function parseFile(filePath: string, raw: string): ParsedFile {
  const rawExt = extname(filePath).toLowerCase();
  const basename = filePath.split("/").pop()?.toLowerCase() ?? "";
  const ext = resolveExtension(rawExt, basename);

  if (MARKDOWN_EXTENSIONS.has(ext)) {
    const { data, content } = matter(raw);
    const hasFrontmatter = Object.keys(data).length > 0;
    return {
      path: filePath,
      content: hasFrontmatter
        ? buildWeightedText(data, content)
        : content.trim(),
      frontmatter: hasFrontmatter ? data : null,
      extension: ext,
    };
  }

  return {
    path: filePath,
    content: raw.trim(),
    frontmatter: null,
    extension: ext,
  };
}

