export async function runBenchmark(
  queries: BenchmarkQuery[],
  db: RagDB,
  projectDir: string,
  topK: number = 5,
  hybridWeight?: number,
): Promise<BenchmarkSummary> {
  const config = await loadConfig(projectDir);
  const weight = hybridWeight ?? config.hybridWeight;

  const results: BenchmarkResult[] = [];

  for (const q of queries) {
    const searchResults = await search(q.query, db, topK, 0, weight, config.generated);

    const resultPaths = searchResults.map((r) => r.path);
    const expectedNormalized = q.expected.map((p) => normalizePath(p, projectDir));

    // Recall: fraction of expected files found in results
    const found = expectedNormalized.filter((e) =>
      resultPaths.some((r) => r === e || r.endsWith(e) || e.endsWith(r))
    );
    const recall = found.length / expectedNormalized.length;

    // Reciprocal rank: 1/rank of first expected file in results
    let reciprocalRank = 0;
    for (let i = 0; i < resultPaths.length; i++) {
      const matchesExpected = expectedNormalized.some(
        (e) => resultPaths[i] === e || resultPaths[i].endsWith(e) || e.endsWith(resultPaths[i])
      );
      if (matchesExpected) {
        reciprocalRank = 1 / (i + 1);
        break;
      }
    }

    results.push({
      query: q.query,
      expected: q.expected,
      results: searchResults.map((r) => ({ path: r.path, score: r.score })),
      recall,
      reciprocalRank,
      hit: found.length > 0,
    });
  }

  const total = results.length;
  const recallAtK = total > 0 ? results.reduce((s, r) => s + r.recall, 0) / total : 0;
  const mrr = total > 0 ? results.reduce((s, r) => s + r.reciprocalRank, 0) / total : 0;
  const misses = results.filter((r) => !r.hit).length;
  const zeroMissRate = total > 0 ? misses / total : 0;

  return { total, recallAtK, mrr, zeroMissRate, results };
}

export async function runEval(
  tasks: EvalTask[],
  db: RagDB,
  projectDir: string,
  topK: number = 5
): Promise<EvalSummary> {
  const traces: EvalTrace[] = [];

  for (const task of tasks) {
    const withRag = await runEvalTask(task, db, projectDir, "with-rag", topK);
    const withoutRag = await runEvalTask(task, db, projectDir, "without-rag", topK);
    traces.push(withRag, withoutRag);
  }

  const withRagTraces = traces.filter((t) => t.condition === "with-rag");
  const withoutRagTraces = traces.filter((t) => t.condition === "without-rag");

  function computeStats(traceSet: EvalTrace[], tasks: EvalTask[]) {
    const n = traceSet.length || 1;
    const avgSearchResults = traceSet.reduce((s, t) => s + t.searchResults.length, 0) / n;
    const avgFilesReferenced = traceSet.reduce((s, t) => s + t.filesReferenced.length, 0) / n;
    const avgDurationMs = traceSet.reduce((s, t) => s + t.durationMs, 0) / n;

    // File hit rate: % of tasks with expectedFiles where at least one was found
    let hits = 0;
    let withExpected = 0;
    for (let i = 0; i < tasks.length; i++) {
      if (tasks[i].expectedFiles && tasks[i].expectedFiles!.length > 0) {
        withExpected++;
        const expected = tasks[i].expectedFiles!;
        const found = traceSet[i].filesReferenced;
        const hasHit = expected.some((e) =>
          found.some((f) => f === e || f.endsWith(e) || e.endsWith(f))
        );
        if (hasHit) hits++;
      }
    }
    const fileHitRate = withExpected > 0 ? hits / withExpected : 0;

    return { avgSearchResults, avgFilesReferenced, avgDurationMs, fileHitRate };
  }

  return {
    totalTasks: tasks.length,
    withRag: computeStats(withRagTraces, tasks),
    withoutRag: computeStats(withoutRagTraces, tasks),
    traces,
  };
}

export async function runGit(args: string[], cwd: string): Promise<string | null> {
  try {
    const proc = Bun.spawn(["git", ...args], { cwd, stdout: "pipe", stderr: "pipe" });
    const output = await new Response(proc.stdout).text();
    const exitCode = await proc.exited;
    return exitCode === 0 ? output.trim() : null;
  } catch {
    return null;
  }
}

