export async function runSetup(projectDir: string, ides?: string[]): Promise<SetupResult> {
  const actions: string[] = [];

  const configAction = await ensureConfig(projectDir);
  if (configAction) actions.push(configAction);

  const instructionActions = await ensureAgentInstructions(projectDir, ides);
  actions.push(...instructionActions);

  const mcpActions = await ensureMcpJson(projectDir, ides);
  actions.push(...mcpActions);

  const gitignoreAction = await ensureGitignore(projectDir);
  if (gitignoreAction) actions.push(gitignoreAction);

  return { actions, unknownIdes: unknownIdes(ides) };
}

export async function saveEvalTraces(traces: EvalTrace[], outputPath: string): Promise<void> {
  await writeFile(outputPath, JSON.stringify(traces, null, 2));
}

export function searchAnnotations(
  db: Database,
  queryEmbedding: Float32Array,
  topK: number = 10
): (AnnotationRow & { score: number })[] {
  return db
    .query<
      {
        annotation_id: number;
        distance: number;
        id: number;
        path: string;
        symbol_name: string | null;
        note: string;
        author: string | null;
        created_at: string;
        updated_at: string;
      },
      [Uint8Array, number]
    >(
      `SELECT v.annotation_id, v.distance,
              a.id, a.path, a.symbol_name, a.note, a.author, a.created_at, a.updated_at
       FROM (SELECT annotation_id, distance FROM vec_annotations WHERE embedding MATCH ? ORDER BY distance LIMIT ?) v
       JOIN annotations a ON a.id = v.annotation_id`
    )
    .all(new Uint8Array(queryEmbedding.buffer), topK)
    .map((row) => ({
      id: row.id,
      path: row.path,
      symbolName: row.symbol_name,
      note: row.note,
      author: row.author,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
      score: 1 / (1 + row.distance),
    }));
}

export function searchCheckpoints(
  db: Database,
  queryEmbedding: Float32Array,
  topK: number = 5,
  type?: string
): (CheckpointRow & { score: number })[] {
  const rows = db
    .query<
      {
        checkpoint_id: number;
        distance: number;
        id: number;
        session_id: string;
        turn_index: number;
        timestamp: string;
        type: string;
        title: string;
        summary: string;
        files_involved: string;
        tags: string;
      },
      [Uint8Array, number]
    >(
      `SELECT v.checkpoint_id, v.distance,
              cp.id, cp.session_id, cp.turn_index, cp.timestamp, cp.type,
              cp.title, cp.summary, cp.files_involved, cp.tags
       FROM (SELECT checkpoint_id, distance FROM vec_checkpoints WHERE embedding MATCH ? ORDER BY distance LIMIT ?) v
       JOIN conversation_checkpoints cp ON cp.id = v.checkpoint_id`
    )
    .all(new Uint8Array(queryEmbedding.buffer), topK * 2);

  const results: (CheckpointRow & { score: number })[] = [];

  for (const row of rows) {
    if (type && row.type !== type) continue;

    results.push({
      id: row.id,
      sessionId: row.session_id,
      turnIndex: row.turn_index,
      timestamp: row.timestamp,
      type: row.type,
      title: row.title,
      summary: row.summary,
      filesInvolved: JSON.parse(row.files_involved || "[]"),
      tags: JSON.parse(row.tags || "[]"),
      score: 1 / (1 + row.distance),
    });

    if (results.length >= topK) break;
  }

  return results;
}

export async function searchCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const query = args[1];
  if (!query) {
    cli.error("Usage: mimirs search <query> [--top N] [--ext .ts,.tsx] [--in src,packages/core] [--exclude tests]");
    process.exit(1);
  }

  const dir = resolve(getFlag("--dir") || ".");
  const db = new RagDB(dir);
  const config = await loadConfig(dir);
  applyEmbeddingConfig(config);
  const top = parseInt(getFlag("--top") || String(config.searchTopK), 10);
  const filter = buildCliFilter(dir, getFlag);

  const results = await search(query, db, top, 0, config.hybridWeight, config.generated, filter);

  if (results.length === 0) {
    cli.log("No results found. Has the directory been indexed?");
  } else {
    for (const r of results) {
      cli.log(`${r.score.toFixed(4)}  ${r.path}`);
      const preview = r.snippets[0]?.slice(0, 120).replace(/\n/g, " ");
      cli.log(`         ${preview}...`);
      cli.log();
    }
  }
  db.close();
}

export function searchConversation(
  db: Database,
  queryEmbedding: Float32Array,
  topK: number = 5,
  sessionId?: string
): ConversationSearchResult[] {
  // Use subquery for vector search, then JOIN for turn data
  const rows = db
    .query<
      {
        chunk_id: number;
        distance: number;
        snippet: string;
        turn_id: number;
        turn_index: number;
        session_id: string;
        timestamp: string;
        summary: string;
        tools_used: string;
        files_referenced: string;
      },
      [Uint8Array, number]
    >(
      `SELECT v.chunk_id, v.distance, cc.snippet, cc.turn_id,
              ct.turn_index, ct.session_id, ct.timestamp, ct.summary, ct.tools_used, ct.files_referenced
       FROM (SELECT chunk_id, distance FROM vec_conversation WHERE embedding MATCH ? ORDER BY distance LIMIT ?) v
       JOIN conversation_chunks cc ON cc.id = v.chunk_id
       JOIN conversation_turns ct ON ct.id = cc.turn_id`
    )
    .all(new Uint8Array(queryEmbedding.buffer), sessionId ? topK * 10 : topK * 3);

  const results: ConversationSearchResult[] = [];
  const seenTurns = new Set<number>();

  for (const row of rows) {
    if (seenTurns.has(row.turn_id)) continue;
    seenTurns.add(row.turn_id);

    if (sessionId && row.session_id !== sessionId) continue;

    results.push({
      turnId: row.turn_id,
      turnIndex: row.turn_index,
      sessionId: row.session_id,
      timestamp: row.timestamp,
      summary: row.summary || "",
      snippet: row.snippet,
      toolsUsed: JSON.parse(row.tools_used || "[]"),
      filesReferenced: JSON.parse(row.files_referenced || "[]"),
      score: 1 / (1 + row.distance),
    });

    if (results.length >= topK) break;
  }

  return results;
}

export function searchGitCommits(
  db: Database,
  queryEmbedding: Float32Array,
  topK: number = 10,
  author?: string,
  since?: string,
  until?: string,
  path?: string
): GitCommitSearchResult[] {
  const hasFilters = !!(author || since || until || path);
  const fetchLimit = hasFilters ? topK * 5 : topK * 2;

  const rows = db
    .query<
      RawRow & { commit_id: number; distance: number },
      [Uint8Array, number]
    >(
      `SELECT v.commit_id, v.distance, gc.*
       FROM (SELECT commit_id, distance FROM vec_git_commits WHERE embedding MATCH ? ORDER BY distance LIMIT ?) v
       JOIN git_commits gc ON gc.id = v.commit_id`
    )
    .all(new Uint8Array(queryEmbedding.buffer), fetchLimit);

  let results: GitCommitSearchResult[] = rows.map((row) => ({
    ...parseRow(row),
    score: 1 / (1 + row.distance),
  }));

  if (hasFilters) {
    results = applyFilters(results, author, since, until, path);
  }

  return results.slice(0, topK);
}

export async function serveCommand() {
  const dir = process.env.RAG_PROJECT_DIR || process.cwd();
  process.stderr.write(`[mimirs] Starting MCP server (stdio) for ${dir}\n`);

  // Dynamic import — server/index.ts has top-level await and native deps
  // (bun:sqlite, sqlite-vec). If they fail at module load time, a static
  // import would crash the entire CLI before any error handler runs,
  // producing no status file and no server-error.log.
  let startServer: typeof import("../../server").startServer;
  try {
    ({ startServer } = await import("../../server"));
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    const stack = err instanceof Error ? err.stack : "(no stack)";
    process.stderr.write(`[mimirs] FATAL: server module failed to load: ${msg}\n`);

    // Write diagnostics so the IDE/user can see what happened
    try {
      const ragDir = join(dir, ".mimirs");
      mkdirSync(ragDir, { recursive: true });
      writeFileSync(
        join(ragDir, "server-error.log"),
        [
          `mimirs server module failed to load at ${new Date().toISOString()}`,
          ``,
          `Error: ${msg}`,
          ``,
          stack,
          ``,
          `To diagnose: bunx mimirs doctor`,
        ].join("\n")
      );
      writeFileSync(
        join(ragDir, "status"),
        [
          `error`,
          `phase: module load failed`,
          `failed: ${new Date().toISOString()}`,
          msg,
        ].join("\n")
      );
    } catch {
      // Best-effort
    }
    throw err;
  }

  await startServer();
  process.stderr.write(`[mimirs] Server ready — listening on stdin/stdout\n`);
}

export async function startServer() {
  // Write "starting" status as the very first thing — overwrites any stale
  // "interrupted" from a previous instance before we do anything else.
  const startupDir = process.env.RAG_PROJECT_DIR || process.cwd();
  const dirCheck = checkIndexDir(startupDir);
  const isHomeDirTrap = !dirCheck.safe;
  const ragDir = join(startupDir, ".mimirs");
  const statusPath = !isHomeDirTrap ? join(ragDir, "status") : null;
  const instanceId = `pid:${process.pid}`;

  let shuttingDown = false;

  const writeStatus = (status: string) => {
    if (!statusPath || shuttingDown) return;
    try {
      mkdirSync(ragDir, { recursive: true });
      writeFileSync(statusPath, `${status}\n${instanceId}`);
    } catch (statusErr) {
      log.warn(`Could not write status: ${statusErr instanceof Error ? statusErr.message : statusErr}`, "status");
    }
  };

  writeStatus(`starting\nversion: ${version}\nstarted: ${new Date().toISOString()}`);

  // Register shutdown handlers early so any crash during startup is recorded.
  // The cleanup targets (watcher, convWatcher) start as null and get assigned
  // later — this is safe because cleanup just skips null values.
  let watcher: Watcher | null = null;
  let convWatcher: Watcher | null = null;


  function writeExitStatus(reason: string) {
    if (!statusPath) return;
    try {
      const current = readFileSync(statusPath, "utf8");
      // Only overwrite if this instance owns the status file.
      // Another instance may have started and written its own status —
      // clobbering it with "interrupted" would be incorrect.
      if (!current.includes(instanceId)) return;
      if (current.startsWith("done") || current.startsWith("error")) return;
      writeFileSync(statusPath, [
        `interrupted`,
        `version: ${version}`,
        `stopped: ${new Date().toISOString()}`,
        `reason: ${reason}`,
        instanceId,
      ].join("\n"));
    } catch (statusErr) {
      log.warn(`Could not write exit status: ${statusErr instanceof Error ? statusErr.message : statusErr}`, "status");
    }
  }

  function cleanup(reason: string = "shutdown") {
    shuttingDown = true;
    writeExitStatus(reason);
    log.debug("Shutting down...", "shutdown");
    if (watcher) watcher.close();
    if (convWatcher) convWatcher.close();
    for (const entry of dbMap.values()) entry.db.close();
    dbMap.clear();
    process.exit(0);
  }


  // Register signal/stdin handlers immediately so crashes during startup
  // still write "interrupted" instead of leaving stale status.
  process.stdin.on("end", () => {
    log.debug("stdin closed (IDE window likely closed)", "shutdown");
    cleanup("stdin closed");
  });
  process.stdin.on("error", () => {
    cleanup("stdin error");
  });
  process.on("SIGINT", () => cleanup("SIGINT"));
  process.on("SIGTERM", () => cleanup("SIGTERM"));
  process.on("SIGHUP", () => cleanup("SIGHUP"));
  process.on("uncaughtException", (err) => {
    log.error(`Uncaught exception: ${err.message}`, "uncaught");
    cleanup(`uncaught exception: ${err.message}\n${err.stack ?? "(no stack)"}`);
  });
  process.on("unhandledRejection", (err) => {
    const msg = err instanceof Error ? err.message : String(err);
    const stack = err instanceof Error ? err.stack : "(no stack)";
    log.error(`Unhandled rejection: ${msg}`, "uncaught");
    cleanup(`unhandled rejection: ${msg}\n${stack}`);
  });

  if (isHomeDirTrap) {
    log.warn(`${dirCheck.reason} — skipping auto-index and file watcher`, "dir-guard");
  }

  writeStatus(`starting\nversion: ${version}\nphase: creating server`);

  let server: McpServer;
  try {
    server = new McpServer({
      name: "mimirs",
      version,
    });

    // Register all MCP tools
    registerAllTools(server, getDB, getConnectedDBs, writeStatus);
    writeStatus(`starting\nversion: ${version}\nphase: tools registered`);
  } catch (err) {
    // If we crash before connecting transport, the MCP client just sees
    // "Connection closed" with no details. Write diagnostics to a file.
    writeStartupError(err);
    writeStatus(`error\nversion: ${version}\nphase: tool registration failed\n${err instanceof Error ? err.message : err}`);
    throw err;
  }

  // Connect transport IMMEDIATELY so the MCP client's `initialize` handshake
  // is answered before any slow startup work (config I/O, session discovery,
  // indexing).  Without this, the client may time out, close the pipes, and
  // the server's subsequent stderr writes hit EPIPE.
  const transport = new StdioServerTransport();
  try {
    writeStatus(`starting\nversion: ${version}\nphase: connecting transport`);
    await server.connect(transport);
    writeStatus(`starting\nversion: ${version}\nphase: transport connected`);
  } catch (err) {
    writeStartupError(err);
    writeStatus(`error\nversion: ${version}\nphase: transport failed\n${err instanceof Error ? err.message : err}`);

    throw err;
  }

  // Preflight: verify DB can be created (catches missing Homebrew SQLite on macOS)
  let startupDb: ReturnType<typeof getDB>;
  try {
    startupDb = getDB(startupDir);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    const isTransient = msg.includes("database is locked") || msg.includes("SQLITE_BUSY");
    const fix = msg.includes("brew install sqlite")
      ? `Fix: run "brew install sqlite" and restart your editor.`
      : msg.includes("EROFS") || msg.includes("EACCES")
        ? `Fix: set RAG_DB_DIR to a writable directory in your MCP config.`
        : `Check the mimirs README for setup instructions.`;

    if (isTransient) {
      // Transient lock — another process was briefly holding the DB.
      // Don't cache the error; the next tool call will retry getDB().
      log.warn(`Startup DB open failed (transient, will retry on next tool call): ${msg}`, "db");
    } else {
      // Permanent failure — cache so every tool call gets a clear message
      permanentError = `${msg}\n\n${fix}`;
      log.error(`FATAL: ${msg} — ${fix}`, "db");
    }

    // Write the error to status so it's visible to the user/IDE
    try {
      mkdirSync(ragDir, { recursive: true });
      writeFileSync(join(ragDir, "status"), [
        isTransient ? `starting` : `error`,
        `version: ${version}`,
        `failed: ${new Date().toISOString()}`,
        msg,
        ``,
        isTransient ? `Will retry on next tool call` : fix,
      ].join("\n"));
    } catch (statusErr) {
      log.warn(`Could not write status: ${statusErr instanceof Error ? statusErr.message : statusErr}`, "status");
    }

    // For permanent errors, tool calls hit the permanentError guard.
    // For transient errors, tool calls retry getDB() which may succeed.
    // Either way, skip startup indexing — it requires an open DB.
    return;
  }

  const startupConfig = await loadConfig(startupDir);

  if (!isHomeDirTrap) {
    // Ensure .mimirs/ is gitignored
    ensureGitignore(startupDir).catch((err) => {
      log.warn(`Failed to update .gitignore: ${err instanceof Error ? err.message : err}`, "gitignore");
    });

    // Index in background — don't block server startup
    let totalFiles = 0;
    let processedFiles = 0;

    indexDirectory(startupDir, startupDb, startupConfig, (msg, progressOpts) => {

      if (msg === "file:done") {
        processedFiles++;
        if (totalFiles > 0) {
          const pct = Math.round((processedFiles / totalFiles) * 100);
          writeStatus(`${processedFiles}/${totalFiles} files (${pct}%)`);
        }
        return;
      }

      log.debug(msg, "indexer");

      // File scanning progress
      if (msg.startsWith("scanning files")) {
        writeStatus(msg);
        return;
      }

      // Model loading messages from embedder
      if (msg.startsWith("Loading embedding model") || msg.startsWith("Retrying model load")) {
        writeStatus(msg);
        return;
      }
      if (msg === "Model loaded") return;

      const foundMatch = msg.match(/^Found (\d+) files to index$/);
      if (foundMatch) {
        totalFiles = parseInt(foundMatch[1], 10);
        writeStatus(`0/${totalFiles} files`);
        return;
      }

      // Show per-file activity so status doesn't stay stuck on "0/N"
      if (totalFiles > 0 && !progressOpts?.transient) {
        const pct = Math.round((processedFiles / totalFiles) * 100);
        writeStatus(`${processedFiles}/${totalFiles} files (${pct}%)\n${msg}`);
      }
    }).then((result) => {
      const dbStatus = startupDb.getStatus();
      const doneStatus = [
        `done`,
        `version: ${version}`,
        `finished: ${new Date().toISOString()}`,
        `indexed: ${result.indexed}, skipped: ${result.skipped}, pruned: ${result.pruned}`,
        `total files: ${dbStatus.totalFiles}, total chunks: ${dbStatus.totalChunks}`,
      ].join("\n");
      writeStatus(doneStatus);
      log.debug(`Startup index: ${result.indexed} indexed, ${result.skipped} skipped, ${result.pruned} pruned`, "indexer");

      // Start watching after initial index completes
      watcher = startWatcher(startupDir, startupDb, startupConfig, (msg) => {
        log.debug(msg, "watcher");
        // Update status file so IDE/client sees watcher activity
        const dbStatus = startupDb.getStatus();
        writeStatus([
          `done`,
          `version: ${version}`,
          `finished: ${new Date().toISOString()}`,
          `total files: ${dbStatus.totalFiles}, total chunks: ${dbStatus.totalChunks}`,
          `watcher: ${msg}`,
        ].join("\n"));

      });
    }).catch((err) => {
      writeStatus(`error\nversion: ${version}\nfailed: ${new Date().toISOString()}\n${err instanceof Error ? err.message : err}`);
      log.warn(`Startup indexing failed: ${err instanceof Error ? err.message : err}`, "indexer");
    });
  }

  // Start conversation tailing — find and tail the current session's JSONL
  const sessions = discoverSessions(startupDir);
  if (sessions.length > 0) {
    // Tail the most recent session (likely the current one)
    const currentSession = sessions[0];
    log.debug(`Indexing conversation: ${currentSession.sessionId.slice(0, 8)}...`, "conversation");

    convWatcher = startConversationTail(
      currentSession.jsonlPath,
      currentSession.sessionId,
      startupDb,
      (msg) => log.debug(msg, "conversation")
    );

    // Also index any older sessions that haven't been indexed yet
    for (const session of sessions.slice(1)) {
      const existing = startupDb.getSession(session.sessionId);
      if (!existing || existing.mtime < session.mtime) {
        indexConversation(
          session.jsonlPath,
          session.sessionId,
          startupDb
        ).then((result) => {
          if (result.turnsIndexed > 0) {
            log.debug(`Indexed past session ${session.sessionId.slice(0, 8)}...: ${result.turnsIndexed} turns`, "conversation");
          }
        }).catch((err) => {
          log.warn(`Failed to index session ${session.sessionId.slice(0, 8)}: ${err instanceof Error ? err.message : err}`, "conversation");
        });
      }
    }
  }

}

export function startWatcher(
  directory: string,
  db: RagDB,
  config: RagConfig,
  onEvent?: (msg: string) => void
): Watcher {
  const pending = new Map<string, NodeJS.Timeout>();

  // Pre-compile globs once instead of per-event
  const excludeGlobs = config.exclude.map((pat) => new Glob(pat));
  const includeGlobs = config.include.map((pat) => new Glob(pat));


  function matchesAny(filePath: string, globs: Glob[]): boolean {
    return globs.some((g) => g.match(filePath));
  }


  // Serial queue: prevents concurrent indexFile + buildPathToIdMap from interleaving.
  // While one cycle runs, new files accumulate in nextBatch and get processed next.
  let processing = false;
  const nextBatch = new Map<string, "index" | "remove">();


  async function processQueue() {
    if (processing) return;
    processing = true;

    try {
      while (nextBatch.size > 0) {
        // Snapshot and clear the batch so new events accumulate into a fresh batch
        const batch = new Map(nextBatch);
        nextBatch.clear();

        for (const [absPath, action] of batch) {
          const rel = relative(directory, absPath);

          if (action === "remove") {
            const removed = db.removeFile(absPath);
            if (removed) onEvent?.(`Removed deleted file: ${rel}`);
            continue;
          }

          const result = await indexFile(absPath, db, config);
          if (result === "indexed") {
            const file = db.getFileByPath(absPath);
            if (file) {
              // Build lookups once and reuse for all resolve calls.
              // Safe because the queue ensures no concurrent indexFile is running.
              const pathToId = buildPathToIdMap(db);
              const idToPath = buildIdToPathMap(pathToId);
              resolveImportsForFile(db, file.id, directory, pathToId, idToPath);
              for (const importerId of db.getImportersOf(file.id)) {
                resolveImportsForFile(db, importerId, directory, pathToId, idToPath);
              }
            }
            onEvent?.(`Re-indexed: ${rel}`);
          }
        }
      }
    } finally {
      processing = false;
    }
  }


  const fsWatcher = watch(directory, { recursive: true }, (_event, filename) => {
    if (!filename) return;

    const rel = filename.toString();

    if (matchesAny(rel, excludeGlobs)) return;
    if (!matchesAny(rel, includeGlobs)) return;

    const absPath = resolve(directory, rel);

    const existing = pending.get(absPath);
    if (existing) clearTimeout(existing);

    pending.set(
      absPath,
      setTimeout(() => {
        pending.delete(absPath);

        if (!existsSync(absPath)) {
          nextBatch.set(absPath, "remove");
        } else {
          nextBatch.set(absPath, "index");
        }

        processQueue();
      }, DEBOUNCE_MS)
    );
  });

  onEvent?.(`Watching ${directory} for changes`);
  return {
    close() {
      for (const timer of pending.values()) clearTimeout(timer);
      pending.clear();
      fsWatcher.close();
    },
  };
}

export async function statusCommand(args: string[]) {
  const dir = resolve(args[1] && !args[1].startsWith("--") ? args[1] : ".");
  const db = new RagDB(dir);
  const status = db.getStatus();
  cli.log(`Index status for ${dir}:`);
  cli.log(`  Files:        ${status.totalFiles}`);
  cli.log(`  Chunks:       ${status.totalChunks}`);
  cli.log(`  Last indexed: ${status.lastIndexed || "never"}`);
  db.close();
}

export function textSearch(
  db: Database,
  query: string,
  topK: number = 5,
  filter?: PathFilter,
): SearchResult[] {
  const { clauses, params: filterParams, active } = buildPathFilter(filter);
  const extraWhere = clauses.length > 0 ? ` AND ${clauses.join(" AND ")}` : "";
  const fetchLimit = active ? topK * FILTER_OVERFETCH : topK;

  const sql = `SELECT c.snippet, c.chunk_index, c.entity_name, c.chunk_type, f.path, rank
     FROM fts_chunks fts
     JOIN chunks c ON c.id = fts.rowid
     JOIN files f ON f.id = c.file_id
     WHERE fts_chunks MATCH ?${extraWhere}
     ORDER BY rank
     LIMIT ?`;

  return db
    .query<
      {
        snippet: string;
        chunk_index: number;
        entity_name: string | null;
        chunk_type: string | null;
        rank: number;
        path: string;
      },
      (string | number)[]
    >(sql)
    .all(sanitizeFTS(query), ...filterParams, fetchLimit)
    .slice(0, topK)
    .map((row) => ({
      path: row.path,
      score: 1 / (1 + Math.abs(row.rank)),
      snippet: row.snippet,
      chunkIndex: row.chunk_index,
      entityName: row.entity_name,
      chunkType: row.chunk_type,
    }));
}

export function textSearchChunks(
  db: Database,
  query: string,
  topK: number = 8,
  filter?: PathFilter,
): ChunkSearchResult[] {
  const { clauses, params: filterParams, active } = buildPathFilter(filter);
  const extraWhere = clauses.length > 0 ? ` AND ${clauses.join(" AND ")}` : "";
  const fetchLimit = active ? topK * FILTER_OVERFETCH : topK;

  const sql = `SELECT c.snippet, c.chunk_index, c.entity_name, c.chunk_type, c.start_line, c.end_line,
            c.parent_id, f.path, rank
     FROM fts_chunks fts
     JOIN chunks c ON c.id = fts.rowid
     JOIN files f ON f.id = c.file_id
     WHERE fts_chunks MATCH ?${extraWhere}
     ORDER BY rank
     LIMIT ?`;

  return db
    .query<
      {
        snippet: string;
        chunk_index: number;
        entity_name: string | null;
        chunk_type: string | null;
        start_line: number | null;
        end_line: number | null;
        parent_id: number | null;
        rank: number;
        path: string;
      },
      (string | number)[]
    >(sql)
    .all(sanitizeFTS(query), ...filterParams, fetchLimit)
    .slice(0, topK)
    .map((row) => ({
      path: row.path,
      score: 1 / (1 + Math.abs(row.rank)),
      content: row.snippet,
      chunkIndex: row.chunk_index,
      entityName: row.entity_name,
      chunkType: row.chunk_type,
      startLine: row.start_line,
      endLine: row.end_line,
      parentId: row.parent_id,
    }));
}

export function textSearchConversation(
  db: Database,
  query: string,
  topK: number = 5,
  sessionId?: string
): ConversationSearchResult[] {
  const rows = db
    .query<
      {
        snippet: string;
        turn_id: number;
        rank: number;
        turn_index: number;
        session_id: string;
        timestamp: string;
        summary: string;
        tools_used: string;
        files_referenced: string;
      },
      [string, number]
    >(
      `SELECT cc.snippet, cc.turn_id, rank,
              ct.turn_index, ct.session_id, ct.timestamp, ct.summary, ct.tools_used, ct.files_referenced
       FROM fts_conversation fts
       JOIN conversation_chunks cc ON cc.id = fts.rowid
       JOIN conversation_turns ct ON ct.id = cc.turn_id
       WHERE fts_conversation MATCH ?
       ORDER BY rank
       LIMIT ?`
    )
    .all(sanitizeFTS(query), sessionId ? topK * 10 : topK * 3);

  const results: ConversationSearchResult[] = [];
  const seenTurns = new Set<number>();

  for (const row of rows) {
    if (seenTurns.has(row.turn_id)) continue;
    seenTurns.add(row.turn_id);

    if (sessionId && row.session_id !== sessionId) continue;

    results.push({
      turnId: row.turn_id,
      turnIndex: row.turn_index,
      sessionId: row.session_id,
      timestamp: row.timestamp,
      summary: row.summary || "",
      snippet: row.snippet,
      toolsUsed: JSON.parse(row.tools_used || "[]"),
      filesReferenced: JSON.parse(row.files_referenced || "[]"),
      score: 1 / (1 + Math.abs(row.rank)),
    });

    if (results.length >= topK) break;
  }

  return results;
}

export function textSearchGitCommits(
  db: Database,
  query: string,
  topK: number = 10,
  author?: string,
  since?: string,
  until?: string,
  path?: string
): GitCommitSearchResult[] {
  const hasFilters = !!(author || since || until || path);
  const fetchLimit = hasFilters ? topK * 5 : topK * 2;

  const rows = db
    .query<
      RawRow & { rank: number },
      [string, number]
    >(
      `SELECT gc.*, fts.rank
       FROM fts_git_commits fts
       JOIN git_commits gc ON gc.id = fts.rowid
       WHERE fts_git_commits MATCH ?
       ORDER BY fts.rank
       LIMIT ?`
    )
    .all(sanitizeFTS(query), fetchLimit);

  let results: GitCommitSearchResult[] = rows.map((row) => ({
    ...parseRow(row),
    score: 1 / (1 + Math.abs(row.rank)),
  }));

  if (hasFilters) {
    results = applyFilters(results, author, since, until, path);
  }

  return results.slice(0, topK);
}

export function unknownIdes(ides?: string[]): string[] {
  if (!ides) return [];
  const known = new Set<string>(KNOWN_IDES);
  return ides.filter(ide => !known.has(ide));
}

export function updateSessionStats(db: Database, sessionId: string, turnCount: number, totalTokens: number, readOffset: number) {
