export function upsertFile(
  db: Database,
  path: string,
  hash: string,
  chunks: EmbeddedChunk[]
) {
  const fileId = upsertFileStart(db, path, hash);
  insertChunkBatch(db, fileId, chunks, 0);
}

export function upsertFileGraph(
  db: Database,
  fileId: number,
  imports: { name: string; source: string; isDefault?: boolean; isNamespace?: boolean }[],
  exports: { name: string; type: string; isDefault?: boolean; isReExport?: boolean; reExportSource?: string }[]
) {
  const tx = db.transaction(() => {
    db.run("DELETE FROM file_imports WHERE file_id = ?", [fileId]);
    db.run("DELETE FROM file_exports WHERE file_id = ?", [fileId]);

    for (const imp of imports) {
      db.run(
        "INSERT INTO file_imports (file_id, source, names, is_default, is_namespace) VALUES (?, ?, ?, ?, ?)",
        [fileId, imp.source, imp.name, imp.isDefault ? 1 : 0, imp.isNamespace ? 1 : 0]
      );
    }

    for (const exp of exports) {
      db.run(
        "INSERT INTO file_exports (file_id, name, type, is_default, is_reexport, reexport_source) VALUES (?, ?, ?, ?, ?, ?)",
        [fileId, exp.name, exp.type, exp.isDefault ? 1 : 0, exp.isReExport ? 1 : 0, exp.reExportSource ?? null]
      );
    }
  });
  tx();
}

export function upsertFileStart(db: Database, path: string, hash: string): number {
  const existing = getFileByPath(db, path);
  if (existing) {
    // UPDATE instead of DELETE+INSERT to preserve files.id — this keeps
    // file_imports.resolved_file_id FKs pointing at this file intact.
    const tx = db.transaction(() => {
      const oldChunks = db
        .query<{ id: number }, [number]>("SELECT id FROM chunks WHERE file_id = ?")
        .all(existing.id);
      for (const c of oldChunks) {
        db.run("DELETE FROM vec_chunks WHERE chunk_id = ?", [c.id]);
      }
      db.run("DELETE FROM chunks WHERE file_id = ?", [existing.id]);
      db.run(
        "UPDATE files SET hash = ?, indexed_at = ? WHERE id = ?",
        [hash, new Date().toISOString(), existing.id]
      );
    });
    tx();
    return existing.id;
  }

  db.run(
    "INSERT INTO files (path, hash, indexed_at) VALUES (?, ?, ?)",
    [path, hash, new Date().toISOString()]
  );
  return Number(
    db.query<{ id: number }, []>("SELECT last_insert_rowid() as id").get()!.id
  );
}

export function upsertSession(
  db: Database,
  sessionId: string,
  jsonlPath: string,
  startedAt: string,
  mtime: number,
  readOffset: number
) {
  db.run(
    `INSERT INTO conversation_sessions (session_id, jsonl_path, started_at, indexed_at, file_mtime, read_offset)
     VALUES (?, ?, ?, ?, ?, ?)
     ON CONFLICT(session_id) DO UPDATE SET
       file_mtime = excluded.file_mtime,
       indexed_at = excluded.indexed_at,
       read_offset = excluded.read_offset`,
    [sessionId, jsonlPath, startedAt, new Date().toISOString(), mtime, readOffset]
  );
}

export function vectorSearch(
  db: Database,
  queryEmbedding: Float32Array,
  topK: number = 5,
  filter?: PathFilter,
): SearchResult[] {
  const { clauses, params: filterParams, active } = buildPathFilter(filter);
  const whereClause = clauses.length > 0 ? `WHERE ${clauses.join(" AND ")}` : "";
  const innerLimit = active ? topK * FILTER_OVERFETCH : topK;

  const sql = `SELECT v.chunk_id, v.distance, c.snippet, c.chunk_index, c.entity_name, c.chunk_type, f.path
     FROM (SELECT chunk_id, distance FROM vec_chunks WHERE embedding MATCH ? ORDER BY distance LIMIT ?) v
     JOIN chunks c ON c.id = v.chunk_id
     JOIN files f ON f.id = c.file_id
     ${whereClause}
     ORDER BY v.distance
     LIMIT ?`;

  return db
    .query<
      {
        chunk_id: number;
        distance: number;
        snippet: string;
        chunk_index: number;
        entity_name: string | null;
        chunk_type: string | null;
        path: string;
      },
      (Uint8Array | number | string)[]
    >(sql)
    .all(new Uint8Array(queryEmbedding.buffer), innerLimit, ...filterParams, topK)
    .map((row) => ({
      path: row.path,
      score: 1 / (1 + row.distance),
      snippet: row.snippet,
      chunkIndex: row.chunk_index,
      entityName: row.entity_name,
      chunkType: row.chunk_type,
    }));
}

