export async function writeFixture(
  dir: string,
  relativePath: string,
  content: string
): Promise<string> {
  const fullPath = join(dir, relativePath);
  const parentDir = fullPath.substring(0, fullPath.lastIndexOf("/"));
  await mkdir(parentDir, { recursive: true });
  await writeFile(fullPath, content);
  return fullPath;
}
